map "http://ahdis.ch/matchbox/fml/translatecoding" = "translatecoding"

uses "http://hl7.org/fhir/StructureDefinition/QuestionnaireResponse" alias QuestionnaireResponse as source
uses "http://hl7.org/fhir/StructureDefinition/ExplanationOfBenefit" alias ExplanationOfBenefit as target

conceptmap "sample-concept-map" {
  prefix a = "http://loinc.org"
  prefix t = "http://snomed.info/sct"

  a: "36554-4" == t: "112283007"
}

group coding(source src : QuestionnaireResponse, target tgt : ExplanationOfBenefit) {
    src.item as item -> tgt as eob then item(item, eob);
}
  
group item(source src, target tgt: ExplanationOfBenefit) {
   src.item as item where linkId in ('coding') log (src.item.linkId) then {
        item.answer as answer log (item.answer) then {
              answer.value as code -> tgt.type = translate(code, '#sample-concept-map', 'CodeableConcept') "translate";
              answer.value as code -> tgt.item as item, item.location = translate(code, '#sample-concept-map', 'CodeableConcept') "translate";
        } "answer";    
   } "item";    
}
